def bits_to_bytes(bits):
    return (bits + 7) // 8

def get_checksum(entropy_bytes):
    h = hashlib.sha256(entropy_bytes).digest()
    return h[0]

def generate_mnemonic():
    entropy = secrets.randbits(128)
    entropy_bytes = entropy.to_bytes(16, byteorder='big')
    checksum = get_checksum(entropy_bytes)
    checksum_bits = checksum >> 4
    combined = (entropy << 4) | checksum_bits
    words = []
    for i in range(12):
        index = (combined >> (11 * (11 - i))) & 0x7FF
        words.append(BIP39_WORDLIST[index])
    return ' '.join(words)

def verify_mnemonic(mnemonic):
    words = mnemonic.split()
    if len(words) != 12:
        return False
    indices = []
    for word in words:
        if word not in BIP39_WORDLIST:
            return False
        indices.append(BIP39_WORDLIST.index(word))
    combined = 0
    for index in indices:
        combined = (combined << 11) | index
    checksum_bits = combined & 0xF
    entropy_bits = combined >> 4
    entropy_bytes = entropy_bits.to_bytes(16, byteorder='big')
    expected_checksum = get_checksum(entropy_bytes) >> 4
    return checksum_bits == expected_checksum

def generate_mnemonics(count, output_file):
    valid_count = 0
    with open(output_file, 'w') as f:
        while valid_count < count:
            mnemonic = generate_mnemonic()
            if verify_mnemonic(mnemonic):
                f.write(mnemonic + '\n')
                valid_count += 1

if __name__ == '__main__':
    import sys
    output_file = sys.argv[1] if len(sys.argv) > 1 else 'mnemonics.txt'
    count = int(sys.argv[2]) if len(sys.argv) > 2 else 300
    generate_mnemonics(count, output_file)
    print(f'Generated {count} valid mnemonics and saved to {output_file}')
